css:
.loader { position: relative; width: 150px; height: 80px; }
.blade {
  position: absolute;
  bottom: 16px;
  width: 8px;
  height: 62px;
  border-radius: 6px;
  background: #666666;
  transform-origin: bottom center;
}
.blade::before {
  content: "";
  position: absolute;
  left: 2px;
  bottom: 12px;
  width: 4px;
  height: 0;
  border-radius: 999px;
  filter: blur(.3px);
  animation: laserGrow 1.6s ease-in-out infinite;
}
.left { left: 28px; transform: rotate(62deg); }
.right { right: 28px; transform: rotate(-62deg); }
.left::before { background: #22c55e; box-shadow: 0 0 12px #22c55e, 0 0 30px #22c55e; }
.right::before { background: #ef4444; box-shadow: 0 0 12px #ef4444, 0 0 30px #ef4444; }
.spark { position: absolute; left: 50%; top: 38px; width: 6px; height: 6px; border-radius: 50%; background: #ffffff; box-shadow: 0 0 14px #ffffff; opacity: 0; animation: duelSpark 1.6s infinite; }
.s2 { animation-delay: .15s; }
.s3 { animation-delay: .3s; }
.s4 { animation-delay: .45s; }
@keyframes laserGrow { 0%,15% { height: 0; } 35%,75% { height: 72px; } 100% { height: 0; } }
@keyframes duelSpark { 0%, 42%, 100% { transform: translate(0,0) scale(.2); opacity: 0; } 48% { opacity: 1; } 60% { transform: translate(calc((var(--x, 1)) * 28px), -24px) scale(1); opacity: 0; } }
.s1 { --x: -1; } .s2 { --x: 1; } .s3 { --x: -.5; } .s4 { --x: .5; }
